-- Verification: row counts

do $$
declare
  n_sources   bigint;
  n_snapshots bigint;
  n_objects   bigint;
begin
  select count(*) into n_sources   from ingest.source_registry;
  select count(*) into n_snapshots from ingest.source_snapshots;
  select count(*) into n_objects   from ingest.raw_objects;

  assert n_sources   >= 22,
    'source_registry: expected >= 22, got ' || n_sources;
  assert n_snapshots >= 42,
    'source_snapshots: expected >= 42, got ' || n_snapshots;
  assert n_objects   >= 219,
    'raw_objects: expected >= 219, got ' || n_objects;

  raise notice 'Phase 2 verification passed: % sources, % snapshots, % objects',
    n_sources, n_snapshots, n_objects;
end $$;

